
CREATE TABLE `accounting_periods` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `period_year` smallint NOT NULL,
  `period_month` tinyint NOT NULL,
  `period_start` date NOT NULL,
  `period_end` date NOT NULL,
  `status` enum('open','closed') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'open',
  `closed_by_user_id` bigint unsigned DEFAULT NULL,
  `closed_by_user_name` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `closed_at` timestamp NULL DEFAULT NULL,
  `reopened_by_user_id` bigint unsigned DEFAULT NULL,
  `reopened_by_user_name` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reopened_at` timestamp NULL DEFAULT NULL,
  `notes` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `accounting_periods_period_year_period_month_unique` (`period_year`,`period_month`)
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `audit_log` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned DEFAULT NULL,
  `user_type` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `branch_id` bigint unsigned DEFAULT NULL,
  `action` varchar(48) COLLATE utf8mb4_unicode_ci NOT NULL,
  `target_table` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `target_id` bigint unsigned DEFAULT NULL,
  `payload` json DEFAULT NULL,
  `ip` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `context` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `audit_log_target_table_target_id_index` (`target_table`,`target_id`),
  KEY `audit_log_user_id_created_at_index` (`user_id`,`created_at`),
  KEY `audit_log_action_created_at_index` (`action`,`created_at`),
  KEY `audit_log_created_at_index` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=257 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `branch_staff` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `role` enum('MANAGER','RECEIVER','COURIER','AUDITOR') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'RECEIVER',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `branch_staff_branch_user_unique` (`branch_id`,`user_id`),
  KEY `branch_staff_user_id_is_active_index` (`user_id`,`is_active`),
  CONSTRAINT `branch_staff_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `tracking_branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `branch_staff_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=573 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `branches` (
