CREATE TABLE `buyer_accounts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `buyer_id` bigint unsigned NOT NULL,
  `balance` decimal(14,2) NOT NULL DEFAULT '0.00',
  `reserved_balance` decimal(14,2) NOT NULL DEFAULT '0.00',
  `total_spent` decimal(14,2) NOT NULL DEFAULT '0.00',
  `total_received` decimal(14,2) NOT NULL DEFAULT '0.00',
  `min_threshold` decimal(14,2) NOT NULL DEFAULT '1000.00',
  `last_reconciled_at` timestamp NULL DEFAULT NULL,
  `last_reconciled_by` bigint unsigned DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `buyer_accounts_buyer_id_unique` (`buyer_id`),
  KEY `buyer_accounts_last_reconciled_by_foreign` (`last_reconciled_by`),
  CONSTRAINT `buyer_accounts_buyer_id_foreign` FOREIGN KEY (`buyer_id`) REFERENCES `buyers` (`id`) ON DELETE CASCADE,
  CONSTRAINT `buyer_accounts_last_reconciled_by_foreign` FOREIGN KEY (`last_reconciled_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `buyer_reconciliations` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `buyer_account_id` bigint unsigned NOT NULL,
  `period_start` date NOT NULL,
  `period_end` date NOT NULL,
  `system_balance` decimal(14,2) NOT NULL,
  `actual_balance` decimal(14,2) NOT NULL,
  `difference` decimal(14,2) NOT NULL,
  `difference_reason` text COLLATE utf8mb4_unicode_ci,
  `adjustment_tx_id` bigint unsigned DEFAULT NULL,
  `attachment_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reconciled_by_id` bigint unsigned NOT NULL,
  `approved_by_id` bigint unsigned DEFAULT NULL,
  `status` enum('PENDING_APPROVAL','APPROVED','REJECTED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING_APPROVAL',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `rejection_reason` text COLLATE utf8mb4_unicode_ci,
  `reconciled_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `approved_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `buyer_reconciliations_adjustment_tx_id_foreign` (`adjustment_tx_id`),
  KEY `buyer_reconciliations_reconciled_by_id_foreign` (`reconciled_by_id`),
  KEY `buyer_reconciliations_approved_by_id_foreign` (`approved_by_id`),
  KEY `buyer_reconciliations_buyer_account_id_period_end_index` (`buyer_account_id`,`period_end`),
  KEY `buyer_reconciliations_status_index` (`status`),
  CONSTRAINT `buyer_reconciliations_adjustment_tx_id_foreign` FOREIGN KEY (`adjustment_tx_id`) REFERENCES `buyer_transactions` (`id`) ON DELETE SET NULL,
  CONSTRAINT `buyer_reconciliations_approved_by_id_foreign` FOREIGN KEY (`approved_by_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `buyer_reconciliations_buyer_account_id_foreign` FOREIGN KEY (`buyer_account_id`) REFERENCES `buyer_accounts` (`id`) ON DELETE CASCADE,
  CONSTRAINT `buyer_reconciliations_reconciled_by_id_foreign` FOREIGN KEY (`reconciled_by_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `buyer_transactions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `buyer_account_id` bigint unsigned NOT NULL,
  `buyer_id` bigint unsigned NOT NULL,
  `type` enum('INITIAL_DEPOSIT','TOP_UP','PURCHASE','PURCHASE_REFUND','RECONCILIATION_ADJUSTMENT','TRANSFER_IN','TRANSFER_OUT','WITHDRAWAL') COLLATE utf8mb4_unicode_ci NOT NULL,
  `amount` decimal(14,2) NOT NULL,
  `balance_before` decimal(14,2) NOT NULL,
  `balance_after` decimal(14,2) NOT NULL,
  `local_amount` decimal(14,2) DEFAULT NULL,
  `local_currency` varchar(3) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `exchange_rate` decimal(18,8) DEFAULT NULL,
  `exchange_rate_id` bigint unsigned DEFAULT NULL,
  `purchase_order_id` bigint unsigned DEFAULT NULL,
  `invoice_image_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `receipt_image_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `proof_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `performed_by_id` bigint unsigned NOT NULL,
  `approved_by_id` bigint unsigned DEFAULT NULL,
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `user_agent` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `transaction_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `buyer_transactions_buyer_id_foreign` (`buyer_id`),
  KEY `buyer_transactions_exchange_rate_id_foreign` (`exchange_rate_id`),
  KEY `buyer_transactions_performed_by_id_foreign` (`performed_by_id`),
  KEY `buyer_transactions_approved_by_id_foreign` (`approved_by_id`),
  KEY `buyer_transactions_buyer_account_id_transaction_date_index` (`buyer_account_id`,`transaction_date`),
  KEY `buyer_transactions_type_transaction_date_index` (`type`,`transaction_date`),
  KEY `buyer_transactions_purchase_order_id_index` (`purchase_order_id`),
  CONSTRAINT `buyer_transactions_approved_by_id_foreign` FOREIGN KEY (`approved_by_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `buyer_transactions_buyer_account_id_foreign` FOREIGN KEY (`buyer_account_id`) REFERENCES `buyer_accounts` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `buyer_transactions_buyer_id_foreign` FOREIGN KEY (`buyer_id`) REFERENCES `buyers` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `buyer_transactions_exchange_rate_id_foreign` FOREIGN KEY (`exchange_rate_id`) REFERENCES `exchange_rates` (`id`) ON DELETE SET NULL,
  CONSTRAINT `buyer_transactions_performed_by_id_foreign` FOREIGN KEY (`performed_by_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `buyer_transactions_purchase_order_id_foreign` FOREIGN KEY (`purchase_order_id`) REFERENCES `purchase_orders` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `buyers` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned NOT NULL,
  `code` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `full_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `primary_warehouse_id` bigint unsigned NOT NULL,
  `max_order_value` decimal(14,2) NOT NULL DEFAULT '5000.00',
  `can_approve_orders` tinyint(1) NOT NULL DEFAULT '0',
  `status` enum('ACTIVE','SUSPENDED','TERMINATED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVE',
  `hired_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `terminated_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `buyers_user_id_unique` (`user_id`),
  UNIQUE KEY `buyers_code_unique` (`code`),
  KEY `buyers_primary_warehouse_id_status_index` (`primary_warehouse_id`,`status`),
  CONSTRAINT `buyers_primary_warehouse_id_foreign` FOREIGN KEY (`primary_warehouse_id`) REFERENCES `warehouses` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `buyers_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `cache` (
